import React, { useEffect, useMemo, useRef, useState } from 'react';
import { formatMessage, _runPostRender, type FormatRenderCtx } from '../../../formatting';
import { MessageAvatar } from './MessageAvatar';
import { MessageActions } from './MessageActions';
import { MessageEditToolbar } from './MessageEditToolbar';
import { SwipeControls } from './SwipeControls';
import { ReasoningBlock } from './ReasoningBlock';
import { MessageMediaWrapper } from './MessageMediaWrapper';

export interface MessageBubbleProps {
  message: {
    mesId: number | string;
    chName: string;
    isUser: boolean;
    isSystem: boolean;
    isError?: boolean;
    bookmarkLink?: string;
    avatarUrl?: string;
    text: string;
    reasoning?: string;
    timestamp?: string;
    tokenCount?: number;
    timer?: number;
    media?: { kind: 'image' | 'file'; url: string; alt?: string }[];
    bias?: string;
    swipes?: { current: number; total: number };
  };
  editing?: boolean;
  onSwipeLeft?: () => void;
  onSwipeRight?: () => void;
  onEdit?: () => void;
  onEditDone?: (text: string) => void;
  onEditCancel?: () => void;
  onDelete?: () => void;
  onCopy?: () => void;
  onBranch?: () => void;
  onCheckpoint?: () => void;
  onTranslate?: () => void;
  onNarrate?: () => void;
  onHide?: () => void;
  onUnhide?: () => void;
  onMoveUp?: () => void;
  onMoveDown?: () => void;
}

// DOM structure mirrors SillyTavern #message_template
// @see SillyTavern/public/index.html lines 7377-7456
export function MessageBubble(props: MessageBubbleProps) {
  const { message, editing } = props;
  const hasBookmark = Boolean(message.bookmarkLink);
  const mesTextRef = useRef<HTMLDivElement>(null);
  const [editText, setEditText] = useState(message.text);

  // Sync edit text when editing starts
  useEffect(() => {
    if (editing) setEditText(message.text);
  }, [editing, message.text]);

  const formatCtx: FormatRenderCtx = useMemo(() => ({
    messageId: message.mesId,
    isUser: message.isUser,
    isSystem: message.isSystem,
    isReasoning: false,
    characterName: message.chName,
  }), [message.mesId, message.isUser, message.isSystem, message.chName]);

  const formattedHtml = useMemo(
    () => formatMessage(message.text ?? '', formatCtx),
    [message.text, formatCtx],
  );

  useEffect(() => {
    if (!mesTextRef.current || editing) return undefined;
    const cleanups = _runPostRender(mesTextRef.current, formatCtx);
    return () => {
      for (const cleanup of cleanups) {
        try {
          cleanup();
        } catch {
          // ignore extension cleanup failures
        }
      }
    };
  }, [editing, formattedHtml, formatCtx]);

  return (
    <div
      className={`mes ${message.isUser ? 'is-user' : ''} ${message.isSystem ? 'is-system' : ''} ${hasBookmark ? 'has-bookmark' : ''} ${message.isError ? 'is-error' : ''}`}
      data-mesid={message.mesId}
      data-is-user={message.isUser}
      data-is-system={message.isSystem}
      data-is-error={!!message.isError}
      data-bookmark-link={message.bookmarkLink ?? ''}
    >
      <MessageAvatar
        avatarUrl={message.avatarUrl}
        mesId={message.mesId}
        timer={message.timer}
        tokenCount={message.tokenCount}
      />

      <button
        className="swipe_left"
        type="button"
        aria-label="Previous swipe"
        onClick={props.onSwipeLeft}
        disabled={!message.swipes || message.swipes.current === 0}
      >
        <i className="fa-solid fa-chevron-left" />
      </button>

      <div className="mes_block">
        <div className="ch_name">
          <div className="flex-container">
            <div className="flex-container">
              <span className="name_text">{message.chName}</span>
              <i className="mes_ghost fa-solid fa-ghost" aria-hidden="true" title="This message is invisible for the AI" />
              <small className="timestamp">{message.timestamp}</small>
            </div>
          </div>

          {!editing && (
            <MessageActions
              isUser={message.isUser}
              isSystem={message.isSystem}
              hasBookmark={hasBookmark}
              onCopy={props.onCopy}
              onEdit={props.onEdit}
              onDelete={props.onDelete}
              onBranch={props.onBranch}
              onCheckpoint={props.onCheckpoint}
              onTranslate={props.onTranslate}
              onNarrate={props.onNarrate}
              onHide={props.onHide}
              onUnhide={props.onUnhide}
            />
          )}

          {editing && (
            <MessageEditToolbar
              onDone={() => props.onEditDone?.(editText)}
              onCancel={props.onEditCancel}
              onCopy={props.onCopy}
              onDelete={props.onDelete}
              onMoveUp={props.onMoveUp}
              onMoveDown={props.onMoveDown}
            />
          )}
        </div>

        {message.reasoning && (
          <ReasoningBlock
            reasoning={message.reasoning}
            onCopy={() => navigator.clipboard?.writeText(message.reasoning ?? '')}
          />
        )}

        {!editing && (
          <div
            className="mes_text"
            ref={mesTextRef}
            dangerouslySetInnerHTML={{ __html: formattedHtml }}
          />
        )}

        {editing && (
          <textarea
            className="mes_edit_textarea"
            value={editText}
            onChange={(e) => setEditText(e.target.value)}
            rows={Math.max(3, editText.split('\n').length)}
            data-testid="mes-edit-textarea"
          />
        )}

        {message.media && message.media.length > 0 && (
          <MessageMediaWrapper items={message.media} />
        )}

        {message.bias && <div className="mes_bias">{message.bias}</div>}
      </div>

      <SwipeControls
        current={message.swipes?.current ?? 0}
        total={message.swipes?.total ?? 0}
        onRight={props.onSwipeRight}
      />
    </div>
  );
}
